<?php
namespace WCPOS\WooCommercePOS\SquareTerminal\Tests\Includes;
use PHPUnit\Framework\TestCase; use WCPOS\WooCommercePOS\SquareTerminal\{WebhookHandler,Settings};
final class FakeVerifier { public array $args=[]; public bool $valid=false; public function verify(string $body,string $sig,string $key,string $url): bool { $this->args=func_get_args(); return $this->valid; }}
final class WebhookHandlerTest extends TestCase { protected function setUp(): void { $GLOBALS['sqtwc_orders']=array(); $GLOBALS['sqtwc_options']['woocommerce_sqtwc_settings']=['webhook_notification_url'=>'https://dev-pro.wcpos.com/wp-json/sqtwc/v1/webhook','webhook_signature_key'=>'secret']; Settings::reset_cache_for_tests(); }
 public function test_invalid_signature_rejects_before_order_lookup_and_uses_explicit_url(): void { $verifier=new FakeVerifier(); $body='{}'; $result=(new WebhookHandler($verifier))->handle($body,['X-Square-HmacSha256-Signature'=>'bad']); self::assertSame(401,$result['status']); self::assertSame('bad',$verifier->args[1]); self::assertSame('https://dev-pro.wcpos.com/wp-json/sqtwc/v1/webhook',$verifier->args[3]); }
 public function test_completed_terminal_checkout_completes_unpaid_order_and_is_idempotent(): void { $order=new \SQTWC_Test_Order(99); $order->update_meta_data('_sqtwc_checkout_idempotency_key','idem'); $GLOBALS['sqtwc_orders'][99]=$order; $verifier=new FakeVerifier(); $verifier->valid=true; $body=json_encode(['event_id'=>'evt_1','type'=>'terminal.checkout.updated','data'=>['object'=>['checkout'=>['status'=>'COMPLETED','reference_id'=>'woocommerce_order_99','payment_ids'=>['pay_1']]]]]); $handler=new WebhookHandler($verifier); $result=$handler->handle($body,['x-square-hmacsha256-signature'=>'sig']); self::assertSame(200,$result['status']); self::assertTrue($order->paid); self::assertSame('pay_1',$order->transaction_id); self::assertSame('',$order->get_meta('_sqtwc_checkout_idempotency_key')); self::assertSame(['evt_1'],$order->get_meta('_sqtwc_processed_event_ids')); $order->paid=false; $result=$handler->handle($body,['x-square-hmacsha256-signature'=>'sig']); self::assertSame('duplicate',$result['result']); self::assertFalse($order->paid); }
 public function test_wrong_reference_id_rejects(): void { $verifier=new FakeVerifier(); $verifier->valid=true; $body=json_encode(['event_id'=>'evt_2','type'=>'terminal.checkout.updated','data'=>['object'=>['checkout'=>['status'=>'COMPLETED','reference_id'=>'bad','payment_ids'=>[]]]]]); $result=(new WebhookHandler($verifier))->handle($body,['x-square-hmacsha256-signature'=>'sig']); self::assertSame(400,$result['status']); }}
